5255	In
5256	Situation \ref{situation-classical}.
5257	\begin{enumerate}
5258	\item The {\it right derived functors of $F$} are the partial functors
5259	$RF$ associated to cases (1) and (2) of
5260	Situation \ref{situation-classical}.
5261	\item The {\it left derived functors of $F$} are the partial functors
5262	$LF$ associated to cases (3) and (4) of
5263	Situation \ref{situation-classical}.
5264	\item An object $A$ of $\mathcal{A}$ is said to be
5265	{\it right acyclic for $F$}, or {\it acyclic for $RF$}
5266	if $A[0]$ computes $RF$.
5267	\item An object $A$ of $\mathcal{A}$ is said to be
5268	{\it left acyclic for $F$}, or {\it acyclic for $LF$}
5269	if $A[0]$ computes $LF$.
5270	\end{enumerate}
5271	\end{definition}
